export function setupServiceWorkerUpdatePrompt({ appVersion, baseUrl }) {
  if (typeof window === "undefined" || !("serviceWorker" in navigator)) return;

  const refreshParam = "pejd-sw-refresh";
  const refreshStorageKey = `pejd-sw-refreshed-${appVersion}`;
  let updateBannerElement = null;
  let hasDismissedForSession = false;
  let hasTriggeredRefresh = false;
  let hasReloaded = false;

  const clearRefreshMarker = () => {
    const url = new URL(window.location.href);
    if (!url.searchParams.has(refreshParam)) return;

    url.searchParams.delete(refreshParam);
    window.history.replaceState(null, "", `${url.pathname}${url.search}${url.hash}`);
  };

  const hasAutoRefreshedForVersion = () => {
    try {
      return window.sessionStorage.getItem(refreshStorageKey) === "1";
    } catch {
      return false;
    }
  };

  const markAutoRefreshedForVersion = () => {
    try {
      window.sessionStorage.setItem(refreshStorageKey, "1");
    } catch {
      // Storage can be unavailable in restricted browser modes.
    }
  };

  const reloadPage = () => {
    if (hasReloaded) return;
    hasReloaded = true;
    window.location.reload();
  };

  const removeUpdateBanner = () => {
    if (updateBannerElement) {
      updateBannerElement.remove();
      updateBannerElement = null;
    }
  };

  const showUpdateBanner = (onRefresh) => {
    if (hasDismissedForSession || updateBannerElement) return;

    const banner = document.createElement("div");
    banner.className = "sw-update-banner";
    banner.style.position = "fixed";
    banner.style.left = "50%";
    banner.style.bottom = "16px";
    banner.style.transform = "translateX(-50%)";
    banner.style.zIndex = "9999";
    banner.style.background = "rgba(17, 24, 39, 0.98)";
    banner.style.color = "#ffffff";
    banner.style.border = "1px solid rgba(255, 255, 255, 0.2)";
    banner.style.borderRadius = "10px";
    banner.style.padding = "12px 14px";
    banner.style.boxShadow = "0 12px 28px rgba(0, 0, 0, 0.4)";
    banner.style.display = "flex";
    banner.style.alignItems = "center";
    banner.style.gap = "10px";
    banner.style.maxWidth = "92vw";
    banner.style.fontFamily = "system-ui, -apple-system, Segoe UI, Roboto, sans-serif";
    banner.innerHTML = '<span style="font-size:14px;line-height:1.3">Update available.</span>';

    const refreshButton = document.createElement("button");
    refreshButton.textContent = "Refresh";
    refreshButton.type = "button";
    refreshButton.style.background = "#ec4899";
    refreshButton.style.color = "#ffffff";
    refreshButton.style.border = "0";
    refreshButton.style.borderRadius = "8px";
    refreshButton.style.padding = "8px 12px";
    refreshButton.style.cursor = "pointer";
    refreshButton.addEventListener("click", () => {
      removeUpdateBanner();
      onRefresh();
    });

    const laterButton = document.createElement("button");
    laterButton.textContent = "Later";
    laterButton.type = "button";
    laterButton.style.background = "transparent";
    laterButton.style.color = "#ffffff";
    laterButton.style.border = "1px solid rgba(255,255,255,0.45)";
    laterButton.style.borderRadius = "8px";
    laterButton.style.padding = "8px 10px";
    laterButton.style.cursor = "pointer";
    laterButton.addEventListener("click", () => {
      hasDismissedForSession = true;
      removeUpdateBanner();
    });

    banner.append(refreshButton, laterButton);
    document.body.appendChild(banner);
    updateBannerElement = banner;
  };

  window.addEventListener("load", async () => {
    try {
      clearRefreshMarker();

      const swUrl = `${baseUrl}service-worker.js?build=${appVersion}`;
      const registration = await navigator.serviceWorker.register(swUrl, { updateViaCache: "none" });

      const refreshWithWaitingWorker = ({ automatic = false } = {}) => {
        const waitingWorker = registration.waiting;
        if (!waitingWorker || hasTriggeredRefresh) return false;

        if (automatic) {
          if (hasAutoRefreshedForVersion()) return false;
          markAutoRefreshedForVersion();
        }

        hasTriggeredRefresh = true;
        waitingWorker.postMessage({ type: "SKIP_WAITING" });
        window.setTimeout(reloadPage, 2000);
        return true;
      };

      const promptForUpdate = () => {
        if (refreshWithWaitingWorker({ automatic: true })) return;

        showUpdateBanner(() => {
          refreshWithWaitingWorker();
        });
      };

      if (registration.waiting) promptForUpdate();

      registration.addEventListener("updatefound", () => {
        const installingWorker = registration.installing;
        if (!installingWorker) return;

        installingWorker.addEventListener("statechange", () => {
          if (installingWorker.state === "installed" && navigator.serviceWorker.controller) {
            promptForUpdate();
          }
        });
      });

      setInterval(() => {
        registration.update().catch(() => {
          // Ignore update check errors while offline.
        });
      }, 5 * 60 * 1000);

      navigator.serviceWorker.addEventListener("controllerchange", () => {
        if (!hasTriggeredRefresh) return;
        reloadPage();
      });
    } catch (error) {
      console.warn("Service worker registration failed", error);
    }
  });
}
